mapper.update:
UPDATE iot_device_service_record
SET output_topic = #{outputTopic},
    output_device_timestamp = #{outputDeviceTimestamp},
    output_payload = #{outputPayload},
    updated_at = CURRENT_TIMESTAMP
WHERE product_key = #{productKey}
  AND device_name = #{deviceName}
  AND service_name = #{serviceName}
  AND direction = 'request'
  AND message_id = #{messageId}
  AND is_delete = 0

mapper.select:
SELECT *
FROM iot_device_property_record
WHERE product_key = #{productKey}
  AND device_name = #{deviceKey}
  AND is_delete = 0
ORDER BY created_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM iot_device_property_record
WHERE product_key = #{productKey}
  AND device_name = #{deviceKey}
  AND is_delete = 0

SELECT *
FROM iot_device_property_record
WHERE product_key = #{productKey}
  AND device_name = #{deviceKey}
  AND property_identifier = #{propertyIdentifier}
  AND is_delete = 0
ORDER BY created_at DESC, id DESC
LIMIT 1

SELECT *
FROM iot_device_event_record
WHERE product_key = #{productKey}
  AND device_name = #{deviceKey}
  AND is_delete = 0
ORDER BY created_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM iot_device_event_record
WHERE product_key = #{productKey}
  AND device_name = #{deviceKey}
  AND is_delete = 0

SELECT *
FROM iot_device_service_record
WHERE product_key = #{productKey}
  AND device_name = #{deviceKey}
  AND is_delete = 0
ORDER BY created_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM iot_device_service_record
WHERE product_key = #{productKey}
  AND device_name = #{deviceKey}
